Para que o seu novo projeto no Supabase funcione corretamente com o **MISIMWEB**, você precisa executar o script abaixo no **SQL Editor** do seu painel do Supabase. 

Este código cria as tabelas necessárias, as funções de faturamento (billing), os triggers de perfil e as políticas de segurança (RLS) para garantir que cada usuário veja apenas seus próprios projetos.

### Script de Configuração MISIMWEB Cloud Engine

```sql
-- 1. TABELA DE PERFIS (PROFILES)
CREATE TABLE public.profiles (
  id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
  full_name TEXT,
  bio TEXT,
  avatar_url TEXT,
  credits INTEGER DEFAULT 100,
  plan TEXT DEFAULT 'Starter',
  is_admin BOOLEAN DEFAULT FALSE,
  stripe_customer_id TEXT,
  trial_end_date TIMESTAMPTZ,
  is_trial_active BOOLEAN DEFAULT TRUE,
  days_free INTEGER DEFAULT 30,
  simulations_count INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 2. TABELA DE PROJETOS (PROJECTS)
CREATE TABLE public.projects (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE NOT NULL,
  name TEXT NOT NULL,
  flowsheet_data JSONB DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 3. TABELA DE COMPONENTES (MINERAIS/REAGENTES)
CREATE TABLE public.components (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE, -- NULL para padrões do sistema
  name TEXT NOT NULL,
  formula TEXT,
  density NUMERIC DEFAULT 2.7,
  molecular_weight NUMERIC DEFAULT 0,
  cas_number TEXT,
  class TEXT DEFAULT 'Mineral',
  elemental_composition TEXT,
  work_index NUMERIC DEFAULT 12.0,
  abrasion_index NUMERIC DEFAULT 0.1,
  color TEXT,
  is_selected BOOLEAN DEFAULT TRUE,
  is_default BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 4. TABELA DE EQUAÇÕES E MODELOS CINÉTICOS
CREATE TABLE public.equipment_equations (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE,
  equipment_type TEXT NOT NULL, -- 'FlotationCell', 'Moinho', etc.
  name TEXT NOT NULL,
  formula TEXT,
  parameters JSONB DEFAULT '{}'::jsonb,
  is_system_default BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 5. TABELA DA COMUNIDADE (POSTS)
CREATE TABLE public.community_posts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE NOT NULL,
  title TEXT NOT NULL,
  content TEXT NOT NULL,
  type TEXT DEFAULT 'discussion',
  tags TEXT[],
  views INTEGER DEFAULT 0,
  is_solved BOOLEAN DEFAULT FALSE,
  attachments JSONB DEFAULT '[]'::jsonb,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 6. TABELA DE LIKES DA COMUNIDADE
CREATE TABLE public.community_likes (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  post_id UUID REFERENCES public.community_posts(id) ON DELETE CASCADE NOT NULL,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(post_id, user_id)
);

-- 7. FUNÇÃO PARA CRIAR PERFIL AUTOMATICAMENTE AO CADASTRAR
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, credits, plan)
  VALUES (new.id, new.raw_user_meta_data->>'full_name', 100, 'Starter');
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- 8. FUNÇÃO DE FATURAMENTO DA SIMULAÇÃO (RPC)
-- Chamada pelo App para debitar créditos com segurança no banco
CREATE OR REPLACE FUNCTION public.process_simulation_billing(p_cost_amount INTEGER)
RETURNS JSONB AS $$
DECLARE
    v_current_credits INTEGER;
    v_new_credits INTEGER;
    v_sim_count INTEGER;
BEGIN
    SELECT credits, simulations_count INTO v_current_credits, v_sim_count 
    FROM public.profiles WHERE id = auth.uid();

    IF v_current_credits < p_cost_amount THEN
        RAISE EXCEPTION 'Saldo de créditos insuficiente para executar a simulação.';
    END IF;

    UPDATE public.profiles 
    SET credits = credits - p_cost_amount,
        simulations_count = simulations_count + 1,
        updated_at = NOW()
    WHERE id = auth.uid()
    RETURNING credits, simulations_count INTO v_new_credits, v_sim_count;

    RETURN jsonb_build_object(
        'new_credits', v_new_credits,
        'new_sim_count', v_sim_count
    );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 9. FUNÇÃO DE ESTATÍSTICAS DA COMUNIDADE (RPC)
CREATE OR REPLACE FUNCTION public.get_community_user_stats(p_user_id UUID)
RETURNS JSONB AS $$
DECLARE
    v_post_count INTEGER;
    v_like_count INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_post_count FROM public.community_posts WHERE user_id = p_user_id;
    SELECT COUNT(*) INTO v_like_count FROM public.community_likes WHERE post_id IN (SELECT id FROM public.community_posts WHERE user_id = p_user_id);

    RETURN jsonb_build_object(
        'posts_count', v_post_count,
        'total_likes', v_like_count
    );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 10. POLÍTICAS DE SEGURANÇA (ROW LEVEL SECURITY)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.projects ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.components ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.equipment_equations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.community_posts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.community_likes ENABLE ROW LEVEL SECURITY;

-- Usuários podem ver apenas seus próprios dados (exceto comunidade e padrões)
CREATE POLICY "Profiles self management" ON public.profiles FOR ALL USING (auth.uid() = id);
CREATE POLICY "Projects owner access" ON public.projects FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Components read access" ON public.components FOR SELECT USING (user_id IS NULL OR auth.uid() = user_id);
CREATE POLICY "Components insert access" ON public.components FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Equations access" ON public.equipment_equations FOR ALL USING (user_id IS NULL OR auth.uid() = user_id);
CREATE POLICY "Community read" ON public.community_posts FOR SELECT USING (true);
CREATE POLICY "Community posts access" ON public.community_posts FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Community likes" ON public.community_likes FOR ALL USING (auth.uid() = user_id);

-- Inserindo alguns componentes padrão para o sistema não iniciar vazio
INSERT INTO public.components (name, formula, density, class, is_default, is_selected, elemental_composition)
VALUES 
('Quartzo', 'SiO2', 2.65, 'Mineral', true, true, 'Si: 46.7, O: 53.3'),
('Calcopirita', 'CuFeS2', 4.2, 'Mineral', true, true, 'Cu: 34.6, Fe: 30.4, S: 35.0'),
('Pirita', 'FeS2', 5.01, 'Mineral', true, true, 'Fe: 46.5, S: 53.5');
```

### Como aplicar:
1.  Vá ao [Dashboard do Supabase](https://app.supabase.com/).
2.  Selecione seu projeto `hrozdhanaldtpzkavajr`.
3.  No menu lateral esquerdo, clique em **SQL Editor**.
4.  Clique em **New Query**.
5.  Cole o código acima e clique em **Run**.

Isso deixará o seu banco de dados 100% pronto para receber os dados do front-end que já configuramos.

