-- 9. FUNÇÕES (RPCs)

-- Processar faturamento de simulação (Dedução de créditos)
CREATE OR REPLACE FUNCTION process_simulation_billing(p_cost_amount int)
RETURNS jsonb AS $$
DECLARE
  current_credits int;
  new_sim_count int;
BEGIN
  -- 1. Obter créditos atuais
  SELECT credits INTO current_credits FROM public.profiles WHERE id = auth.uid();

  -- 2. Validar créditos
  IF current_credits < p_cost_amount THEN
    RAISE EXCEPTION 'Saldo de créditos insuficiente.';
  END IF;

  -- 3. Atualizar perfil
  UPDATE public.profiles 
  SET 
    credits = credits - p_cost_amount,
    simulations_count = simulations_count + 1,
    updated_at = now()
  WHERE id = auth.uid()
  RETURNING credits, simulations_count INTO current_credits, new_sim_count;

  RETURN jsonb_build_object('new_credits', current_credits, 'new_sim_count', new_sim_count);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Estatísticas da comunidade
CREATE OR REPLACE FUNCTION get_community_user_stats(p_user_id uuid)
RETURNS jsonb AS $$
DECLARE
  post_count int;
  like_count int;
BEGIN
  SELECT count(*) INTO post_count FROM public.community_posts WHERE user_id = p_user_id;
  SELECT count(*) INTO like_count FROM public.community_likes l 
  JOIN public.community_posts p ON l.post_id = p.id 
  WHERE p.user_id = p_user_id;

  RETURN jsonb_build_object('posts_count', post_count, 'total_likes', like_count);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Excluir conta
CREATE OR REPLACE FUNCTION delete_user()
RETURNS void AS $$
BEGIN
  DELETE FROM auth.users WHERE id = auth.uid();
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 10. AUTOMATIZAÇÃO (TRIGGERS)

-- Criar perfil automaticamente no cadastro (Trigger do Auth)
CREATE OR REPLACE FUNCTION public.handle_new_user() 
RETURNS trigger AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, email, credits, plan, is_admin)
  VALUES (
    new.id, 
    new.raw_user_meta_data->>'full_name', 
    new.email, 
    100, 
    'Starter',
    (new.email = 'eng.mateusgsilva@gmail.com') -- Define admin por email específico se necessário
  );
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user();
